"use client";

import { type KeyValueProps, KeyValue as KeyValueRoot, keyValueVariants } from "./key-value";
import type { KeyValueLayout, KeyValueVariant } from "./key-value-context";
import { KeyValueItem, type KeyValueItemProps, labelVariants as keyValueLabelVariants, valueVariants as keyValueValueVariants } from "./key-value-item";

const KeyValue = Object.assign(KeyValueRoot, { Item: KeyValueItem });

export { KeyValue, keyValueVariants, type KeyValueProps, type KeyValueLayout };
export { KeyValueItem, keyValueLabelVariants, keyValueValueVariants, type KeyValueItemProps, type KeyValueVariant };

"use client";

import { cva } from "class-variance-authority";
import { type ComponentPropsWithRef, type ReactNode, useMemo } from "react";
import { cn } from "@/lib/utils";
import { KeyValueContext, type KeyValueLayout } from "./key-value-context";

export const keyValueVariants = cva("grid", {
  variants: {
    layout: {
      horizontal: "grid-cols-[minmax(0,1fr)_auto] items-baseline gap-x-6 gap-y-2",
      vertical: "grid-cols-1 gap-y-1",
    },
    bordered: {
      true: "gap-y-0",
      false: "",
    },
  },
  defaultVariants: { layout: "horizontal", bordered: false },
});

export interface KeyValueProps extends ComponentPropsWithRef<"dl"> {
  layout?: KeyValueLayout;
  bordered?: boolean;
  children: ReactNode;
}

export function KeyValue({
  layout = "horizontal",
  bordered = false,
  children,
  className,
  ref,
  ...props
}: KeyValueProps) {
  const contextValue = useMemo(() => ({ layout, bordered }), [layout, bordered]);

  return (
    <KeyValueContext value={contextValue}>
      <dl
        ref={ref}
        className={cn(keyValueVariants({ layout, bordered }), className)}
        {...props}
      >
        {children}
      </dl>
    </KeyValueContext>
  );
}

"use client";

import { cva } from "class-variance-authority";
import type { ComponentPropsWithRef, ReactNode } from "react";
import { cn } from "@/lib/utils";
import { type KeyValueLayout, type KeyValueVariant, useKeyValueContext } from "./key-value-context";

export interface KeyValueItemProps extends Omit<ComponentPropsWithRef<"dt">, "children"> {
  label: ReactNode;
  value: ReactNode;
  variant?: KeyValueVariant;
  layout?: KeyValueLayout;
  bordered?: boolean;
  labelClassName?: string;
  valueClassName?: string;
}

export const labelVariants = cva("text-muted-foreground", {
  variants: {
    bordered: {
      true: "pt-4 border-t border-border first:border-t-0 text-xs",
      false: "text-sm",
    },
  },
  defaultVariants: { bordered: false },
});

export const valueVariants = cva("", {
  variants: {
    variant: {
      default: "font-bold text-foreground",
      warning: "font-bold text-warning",
      info: "font-mono text-foreground",
      success: "font-bold text-success",
      error: "font-bold text-destructive",
    },
    bordered: { true: "text-xs", false: "" },
    layout: {
      horizontal: "text-right",
      vertical: "pb-3",
    },
  },
  compoundVariants: [
    { layout: "horizontal", bordered: true, class: "pt-4 border-t border-border [&:nth-child(2)]:border-t-0" },
  ],
  defaultVariants: { variant: "default", bordered: false, layout: "horizontal" },
});

export function KeyValueItem({
  label,
  value,
  variant = "default",
  className,
  labelClassName,
  valueClassName,
  ref,
  layout: layoutProp,
  bordered: borderedProp,
  ...rest
}: KeyValueItemProps) {
  const ctx = useKeyValueContext();
  const layout = layoutProp ?? ctx.layout;
  const bordered = borderedProp ?? ctx.bordered;

  return (
    <>
      <dt
        ref={ref}
        className={cn(labelVariants({ bordered }), className, labelClassName)}
        {...rest}
      >
        {label}
      </dt>
      <dd className={cn(valueVariants({ variant, bordered, layout }), valueClassName)}>{value}</dd>
    </>
  );
}

"use client";

import type { VariantProps } from "class-variance-authority";
import { createContext, useContext } from "react";
import type { keyValueVariants } from "./key-value";
import type { valueVariants } from "./key-value-item";

export type KeyValueLayout = NonNullable<VariantProps<typeof keyValueVariants>["layout"]>;
export type KeyValueVariant = NonNullable<VariantProps<typeof valueVariants>["variant"]>;

interface KeyValueContextValue {
  layout: KeyValueLayout;
  bordered: boolean;
}

const KeyValueContext = createContext<KeyValueContextValue | undefined>(undefined);

function useKeyValueContext(): KeyValueContextValue {
  const context = useContext(KeyValueContext);
  if (context === undefined) {
    throw new Error("KeyValue.Item must be used within KeyValue");
  }
  return context;
}

export { KeyValueContext, useKeyValueContext };
